mapper.update:
UPDATE agent_run
SET status = 'running',
    started_at = COALESCE(started_at, #{startedAt}),
    max_steps = #{maxSteps}
WHERE id = #{runId}

UPDATE agent_run
SET status = #{status},
    error = #{error,jdbcType=OTHER,typeHandler=org.congcong.algomentor.agent.persistence.postgres.json.JsonbTypeHandler},
    ended_at = #{endedAt}
WHERE id = #{runId}

UPDATE agent_turn
SET status = 'failed',
    updated_at = #{updatedAt}
WHERE id = #{turnId}
